kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval '
rs.initiate({
  _id: "mongodb-replica",
  members: [
    {_id: 0, host: "mongodb-replica-0.mongodb-replica-svc.mongodb.svc.cluster.local:27017"},
    {_id: 1, host: "mongodb-replica-1.mongodb-replica-svc.mongodb.svc.cluster.local:27017"},
    {_id: 2, host: "mongodb-replica-2.mongodb-replica-svc.mongodb.svc.cluster.local:27017"}
  ]
})
'

kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval '
var maxWait = 30;
for (var i = 0; i < maxWait; i++) {
  var s = rs.status();
  if (s.myState === 1) { print("PRIMARY elected after " + i*2 + "s"); break; }
  print("Waiting... state=" + s.myState);
  sleep(2000);
}
if (rs.status().myState !== 1) { print("ERROR: no PRIMARY"); quit(1); }
'

kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval '
db.getSiblingDB("admin").createUser({
  user: "admin-user",
  pwd: "admin123password",
  roles: [{role: "root", db: "admin"}]
});
print("Admin user created");
'

kubectl exec -n mongodb mongodb-replica-0 -- mongosh \
  --quiet \
  -u admin-user -p admin123password \
  --authenticationDatabase admin \
  --eval '
db.getSiblingDB("appdb").createUser({
  user: "app-user",
  pwd: "app123password",
  roles: [{role: "readWrite", db: "appdb"}]
});
print("App user created");
'

kubectl exec -n mongodb mongodb-replica-0 -- mongosh \
  --quiet \
  -u app-user -p app123password \
  --authenticationDatabase appdb \
  appdb \
  --eval '
db.testCollection.insertOne({message: "Hello from MongoDB replica set", ts: new Date()});
var doc = db.testCollection.findOne({message: "Hello from MongoDB replica set"});
print("Write/read OK: " + doc.message);
'

